## **9. Solutions**

---

### **Solution 1 \u2014 Longest subarray with sum \u2264 K**

```cpp
int i = 0, sum = 0, ans = 0;

for (int j = 0; j < n; j++) {
    sum += arr[j];

    while (sum > k) {
        sum -= arr[i];
        i++;
    }

    ans = max(ans, j - i + 1);
}
```

---

### **Solution 2 \u2014 Pair sum in sorted array**

```cpp
int i = 0, j = n - 1;

while (i < j) {
    int sum = arr[i] + arr[j];
    if (sum == target) { /* print pair */ i++; j--; }
    else if (sum < target) i++;
    else j--;
}
```

---

### **Solution 3 \u2014 Max sum subarray of size K**

```cpp
int sum = 0;
for (int i = 0; i < k; i++) sum += arr[i];

int ans = sum;

for (int i = k; i < n; i++) {
    sum += arr[i] - arr[i-k];
    ans = max(ans, sum);
}
```

---

### **Solution 4 \u2014 Longest substring with at most K distinct**

```cpp
unordered_map<char,int> mp;
int i = 0, ans = 0;

for (int j = 0; j < s.size(); j++) {
    mp[s[j]]++;

    while (mp.size() > k) {
        mp[s[i]]--;
        if (mp[s[i]] == 0) mp.erase(s[i]);
        i++;
    }

    ans = max(ans, j - i + 1);
}
```

---

### **Solution 5 \u2014 Minimum swaps to group 1s**

```cpp
int ones = count(arr.begin(), arr.end(), 1);
int curr = 0;

for (int i = 0; i < ones; i++)
    if (arr[i] == 1) curr++;

int maxOnes = curr;

for (int i = ones; i < n; i++) {
    if (arr[i] == 1) curr++;
    if (arr[i - ones] == 1) curr--;
    maxOnes = max(maxOnes, curr);
}

int minSwaps = ones - maxOnes;
```

